import React, { useEffect, useState } from "react";
import "./HomePage.css";
import Main from "../../Components/Main/Main";
import Home from "../../Components/Home/Home";
import Loading from "../Loading/Loading";

function HomePage() {
  const [loading, setLoading] = useState(true); // Track loading state
  const [homeSliderData, setHomeSliderData] = useState(null); // Store HomeSlider data
  const [productsData, setProductsData] = useState(null); // Store ProductsData
  const [imagesLoaded, setImagesLoaded] = useState(0); // Track number of images loaded

  useEffect(() => {
    window.scrollTo(0, 0);

    const fetchData = async () => {
      try {
        // Dynamically import both data files
        const { HomeSlider } = await import("../../Data/SliderImages");
        const { ProductsData } = await import("../../Data/ProductsData");

        // Set data to state
        setHomeSliderData(HomeSlider);
        setProductsData(ProductsData);
      } catch (error) {
        console.error("Error loading data:", error);
      }
    };

    fetchData(); // Trigger data fetching
  }, []);

  // Function to handle image loading
  const handleImageLoad = () => {
    setImagesLoaded((prev) => prev + 1);
  };

  // Total number of images to load
  const totalImages = homeSliderData?.length + productsData?.flatMap((product) => product.Images).length;

  // Check if all images are loaded
  useEffect(() => {
    if (totalImages && imagesLoaded >= totalImages) {
      setLoading(false); // All images are loaded, hide the spinner
    }
  }, [imagesLoaded, totalImages]);

  if (loading) {
    return <Loading />; // Show loading indicator until data and images are ready
  }

  return (
    <div className="background">
      {/* Pass loaded data and image load handler as props to child components */}
      <Home slides={homeSliderData} onImageLoad={handleImageLoad} />
      <Main images={productsData} onImageLoad={handleImageLoad} />
    </div>
  );
}

export default HomePage;



